canvas.init:
function init(canvas, params) {
  var ctx = canvas.getContext('2d');
  var pairs = params.pairs || 20;
  var speed = params.speed || 0.04;
  var amp = params.amplitude || 40;
  var color = getComputedStyle(canvas).getPropertyValue('--ct-text-strong').trim() || '#ffffff';
  function hexToRgba(h, a) {
    h = h.replace('#','');
    if (h.length === 3) h = h.split('').map(function(c){return c+c;}).join('');
    var r = parseInt(h.slice(0,2),16), g = parseInt(h.slice(2,4),16), b = parseInt(h.slice(4,6),16);
    return 'rgba('+r+','+g+','+b+','+a+')';
  }
  var t = 0;
  function draw() {
    ctx.clearRect(0, 0, 300, 180);
    t += speed;
    for (var i = 0; i < pairs; i++) {
      var y = i * 8 + 15;
      var phase = i * 0.4 + t;
      var xOff = Math.sin(phase) * amp;
      var s1 = Math.cos(phase) * 2 + 3;
      var s2 = Math.cos(phase + Math.PI) * 2 + 3;
      var x1 = 150 + xOff, x2 = 150 - xOff;
      ctx.beginPath();
      ctx.moveTo(x1, y); ctx.lineTo(x2, y);
      ctx.strokeStyle = hexToRgba(color, 0.15);
      ctx.stroke();
      if (Math.cos(phase) > 0) {
        ctx.beginPath(); ctx.arc(x2, y, Math.max(0.5, s2), 0, Math.PI * 2); ctx.fillStyle = hexToRgba(color, 0.2); ctx.fill();
        ctx.beginPath(); ctx.arc(x1, y, Math.max(0.5, s1), 0, Math.PI * 2); ctx.fillStyle = hexToRgba(color, 0.9); ctx.fill();
      } else {
        ctx.beginPath(); ctx.arc(x1, y, Math.max(0.5, s1), 0, Math.PI * 2); ctx.fillStyle = hexToRgba(color, 0.2); ctx.fill();
        ctx.beginPath(); ctx.arc(x2, y, Math.max(0.5, s2), 0, Math.PI * 2); ctx.fillStyle = hexToRgba(color, 0.9); ctx.fill();
      }
    }
    requestAnimationFrame(draw);
  }
  draw();
}
